const text = $input.item.json.output || '';

// Чистим [Used tools]
const cleaned = text.replace(/\[Used tools:.*?\]\s*/gs, '').trim();

// Проверяем флаг удаления
let confirmDelete = null;
try {
  const parsed = JSON.parse(cleaned);
  if (parsed.action === 'confirm_delete') {
    confirmDelete = parsed; // уже объект
  }
} catch (e) {}

return {
  json: {
    ...$input.item.json,
    output: confirmDelete ? '' : cleaned,
    confirm_delete: confirmDelete // объект, не строка
  }
};
